messages.content:
RISKS:
[
 {
  "riskId": "risk.base-rate-analogy.som-window-cumulative-misread",
  "title": "The 1% Year-1 anchor is a 36-month number wearing a 12-month label",
  "claim": "obtainableFactor's 1% rests on Prospeo's staged benchmark, read as an annual snapshot. But Prospeo itself frames SOM as revenue captured over 1-3 years, IdeaPlan says 'one to three years', Wise says 'three to five years', and TryBuildCo's own worked example lands at 0.1% of SAM — below the model's stated floor of 0.5%. The cross-check comparable (Tractian '$1.2M first year') is unverified against its own source, which shows $200K starting revenue. For a pre-launch industrial entrant with zero installed base and no certifications on day 0, the honest 12-month number is the bottom of the reference class, not its midpoint. The whole YAM figure is a period-mismatch error, not a market estimate.",
  "falsifier": "A documented comparable — an industrial hardware entrant into DC infrastructure — that captured ≥1% of a regional SAM in its first 12 months from commercial launch, with dated revenue evidence."
 },
 {
  "riskId": "risk.base-rate-analogy.prelet-lockin-serviceable-window",
  "title": "2026 demand is already specified: the serviceable haircut ignores that reachability has a clock",
  "claim": "serviceableFactor 0.55 is framed as a channel-and-regulatory reach haircut, as if reach were a static property. But for DC electrical gear, the demand that will invoice in the next 12 months was specified at design stage — the model's own cross-check admits 12-24 month procurement lock, and the corpus shows lock-in occurring far earlier (transformer lead times of 48-60 months, hyperscale cycles up to 4-7 years). Meanwhile the entrant's EU compliance stack (WEEE, CE, TÜV, RoHS, plus EN 50600-compatible documentation) consumes 6-9 months from day 0. The intersection of 'demand contestable in months 1-12' and 'entrant qualified to bid' is a fraction of the static 0.55 — the serviceable share within the YAM window is a different, smaller number than the serviceable share of the market in steady state.",
  "falsifier": "Three or more CE operator RFQs for rack PDUs in the next two quarters that (a) accept vendors whose certifications complete during the tender process and (b) award within 9 months of publication."
 },
 {
  "riskId": "risk.base-rate-analogy.framework-foreclosure-beachhead",
  "title": "The chosen beachhead buys through global frameworks: half the large-operator cell is not a market for a regional entrant",
  "claim": "The venture's stated first channel is large operators, and the model gives that cell 40% of PDU spend on the logic 'large operators buy direct'. The corpus shows what 'direct' actually means at that scale: Digital Realty's $373M Schneider framework agreement, Iren's $1.6bn all-in Dell contract, PDU spend embedded as one line inside integrated rack/power/cooling packages. Combined with CR3 ≈ 0.55 among vendors who sell exactly those bundles, the buying event a new entrant needs — a discrete, multi-bidder PDU bake-off at a large operator — is disappearing. The only standalone PDU procurements found in the corpus were small, 1-2 bidder, sometimes explicitly sole-sourced. The beachhead the profile names is the cell most structurally closed to the venture; the model prices it as the biggest open door.",
  "falsifier": "Two named CE large operators (e.g., a Frankfurt or Amsterdam colo/hyperscale buyer) confirming a vendor-neutral, multi-bidder rack-PDU RFQ process in 2026 that is open to suppliers outside existing framework agreements."
 },
 {
  "riskId": "risk.base-rate-analogy.channel-calendar-lockout",
  "title": "Distributor line-cards and integrator qualification run on annual calendars the 12-month plan cannot intersect",
  "claim": "35% of the modeled funnel flows through OEM/integrator (0.22) and distributor (0.13) cells — both admitted internal estimates with zero evidence attached. The reference class says both channels have a calendar: distributor line-card reviews are annual events requiring certifications, stock commitments and demand proof in hand; integrators demonstrably select branded incumbents on certification, DCIM compatibility and support (every case study found — Vertiv/Greenergy, Legrand/MIND Park — shows brand selection, none shows a new entrant winning a slot). A pre-launch vendor with no certs on day 0 misses the current listing cycle entirely and enters the next one as an unproven applicant. Within the YAM window these two cells are not small — they are closed, and the model treats 'closed this year' as indistinguishable from 'open at 35%'.",
  "falsifier": "A signed CE master-distributor listing or OEM/integrator supply agreement with committed volumes, effective within the venture's first six months."
 },
 {
  "riskId": "risk.base-rate-analogy.poc-acceptance-reversal",
  "title": "The industrial-hardware acceptance base rate un-books a third of whatever Year-1 obtains",
  "claim": "Whatever tiny share the venture obtains in year 1 will be obtained as pilots and first deployments — the profile's own 'conservative ramp' guarantees it. The reference class puts a number on what happens next: 30% of deployed industrial hardware systems are never fully accepted — customers sign, the vendor deploys, and six months later the gear comes back out. Intelligent PDUs are acutely exposed because acceptance hinges on post-deployment behavior: DCIM integration, metering accuracy, firmware stability under the operator's monitoring stack. The model's obtainableFactor is a gross booking rate; nothing in the funnel converts it to net-of-reversal, and for a first-year entrant the reversal doesn't just cut revenue — it destroys the reference accounts that the Year-2 3% benchmark silently assumes exist.",
  "falsifier": "The venture's first three CE pilot deployments passing formal customer acceptance within 90 days of install, with no rollback or return clause exercised in the following two quarters."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
